"""Static dashboard styles_css asset."""

STYLES_CSS = ':root{--bg:#f4f7fb;--surface:#fff;--ink:#0f172a;--muted:#64748b;--line:#dbe4ef;--blue:#2563eb;--navy:#0b1220;--green:#15803d;--orange:#c2410c;--red:#b91c1c;--purple:#6d28d9;--shadow:0 16px 50px rgba(15,23,42,.08)}*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;background:var(--bg);color:var(--ink);font-family:-apple-system,BlinkMacSystemFont,"Hiragino Sans","Yu Gothic",Meiryo,Arial,sans-serif;line-height:1.6}.skip-link{position:absolute;left:-9999px}.skip-link:focus{left:12px;top:12px;z-index:100;background:#fff;padding:8px}.topbar{position:sticky;top:0;z-index:50;height:64px;padding:0 max(18px,calc((100vw - 1180px)/2));display:flex;align-items:center;justify-content:space-between;background:rgba(11,18,32,.94);backdrop-filter:blur(14px);color:#fff}.brand{display:flex;gap:10px;align-items:center;font-weight:900;letter-spacing:-.02em}.brand-mark{display:grid;place-items:center;width:32px;height:32px;border-radius:10px;background:linear-gradient(135deg,#60a5fa,#2563eb)}.site-nav{display:flex;gap:18px}.site-nav a{color:#cbd5e1;text-decoration:none;font-size:13px;font-weight:700}.site-nav a:hover{color:#fff}.nav-toggle{display:none;background:transparent;border:0;color:#fff;font-size:24px}.section-shell{max-width:1180px;margin:0 auto;padding:64px 24px 0}.hero{display:grid;grid-template-columns:1.35fr .65fr;gap:30px;align-items:end;padding-top:72px}.hero-copy h1{font-size:clamp(42px,7vw,76px);line-height:1.02;letter-spacing:-.055em;margin:8px 0 18px;max-width:820px}.hero-copy p{font-size:17px;color:#475569;max-width:720px}.eyebrow{font-size:11px;font-weight:900;letter-spacing:.13em;color:var(--blue)}.hero-meta{display:flex;flex-wrap:wrap;gap:9px;margin-top:22px}.hero-meta>span,.status-pill{background:#e8eef7;border:1px solid #d8e2f0;border-radius:999px;padding:6px 11px;font-size:12px;font-weight:800}.status-pill.pass{background:#dcfce7;color:#166534;border-color:#bbf7d0}.status-pill.warn{background:#fff7ed;color:#9a3412;border-color:#fed7aa}.regime-card{min-height:230px;border-radius:26px;padding:28px;background:linear-gradient(145deg,#0f172a,#172554);color:#fff;box-shadow:var(--shadow);display:flex;flex-direction:column;justify-content:flex-end}.regime-score{font-size:64px;line-height:1;font-weight:950;letter-spacing:-.06em}.regime-label{font-size:25px;font-weight:900}.regime-guidance{font-size:13px;color:#cbd5e1;margin-top:12px}.regime-breadth{display:flex;gap:12px;flex-wrap:wrap;margin-top:16px;font-size:11px;color:#dbeafe}.metric-grid{display:grid;grid-template-columns:repeat(6,1fr);gap:12px;padding-top:28px}.metric-card{background:var(--surface);border:1px solid var(--line);border-radius:18px;padding:17px;box-shadow:0 4px 20px rgba(15,23,42,.03)}.metric-label{color:var(--muted);font-size:11px;font-weight:800}.metric-value{font-size:25px;font-weight:950;letter-spacing:-.04em;margin-top:3px}.metric-sub{font-size:11px;color:#94a3b8;margin-top:3px}.section-head{display:flex;justify-content:space-between;gap:24px;align-items:end;margin-bottom:22px}.section-head h2{font-size:34px;letter-spacing:-.035em;margin:5px 0 4px}.section-head p{margin:0;color:var(--muted);max-width:720px}.count-strip{display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end}.count-chip{border-radius:999px;background:#e8eef7;padding:6px 10px;font-size:12px;font-weight:900}.count-chip.a{background:#dcfce7;color:#166534}.count-chip.b{background:#dbeafe;color:#1d4ed8}.count-chip.c{background:#fef3c7;color:#92400e}.count-chip.watch{background:#ede9fe;color:#6d28d9}.count-chip.skip{background:#e2e8f0;color:#475569}.action-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}.action-card{background:#fff;border-radius:22px;padding:21px;border:1px solid var(--line);box-shadow:0 7px 30px rgba(15,23,42,.04);position:relative;overflow:hidden}.action-card:before{content:"";position:absolute;left:0;top:0;bottom:0;width:5px;background:var(--blue)}.action-card.bucket-a:before{background:var(--green)}.action-top{display:flex;justify-content:space-between;gap:14px}.action-title{font-size:18px;font-weight:950}.bucket-badge{font-size:12px;font-weight:950;border-radius:999px;padding:5px 9px;background:#dbeafe;color:#1d4ed8}.bucket-a .bucket-badge{background:#dcfce7;color:#166534}.action-score{font-size:27px;font-weight:950}.tag-row{display:flex;gap:6px;flex-wrap:wrap;margin-top:10px}.tag{font-size:10px;font-weight:850;padding:4px 7px;border-radius:999px;background:#eef2ff;color:#4338ca}.action-block{margin-top:12px;font-size:12px;color:#334155}.action-block b{display:block;color:#0f172a;margin-bottom:2px}.risk{color:#9a3412}.next{color:#334155}.filter-panel{background:#fff;border:1px solid var(--line);border-radius:20px;padding:16px;display:grid;grid-template-columns:2fr repeat(4,1fr) auto auto;gap:11px;align-items:end}.filter-panel label{font-size:11px;color:var(--muted);font-weight:800}.filter-panel label span{display:block;margin-bottom:5px}.filter-panel input,.filter-panel select{width:100%;height:40px;border:1px solid #cbd5e1;border-radius:10px;background:#fff;padding:0 10px;color:#0f172a}.filter-panel .check{display:flex;gap:7px;align-items:center;height:40px;color:#334155}.filter-panel .check span{margin:0;white-space:nowrap}.filter-panel .check input{width:17px;height:17px}.ghost-button,.download-button{border:1px solid #cbd5e1;background:#fff;color:#334155;border-radius:11px;padding:9px 12px;font-weight:800;text-decoration:none;cursor:pointer}.download-button{background:var(--blue);color:#fff;border-color:var(--blue)}.table-meta{display:flex;justify-content:space-between;color:var(--muted);font-size:11px;padding:12px 3px}.table-wrap{overflow:auto;background:#fff;border:1px solid var(--line);border-radius:18px}.data-table{border-collapse:collapse;width:100%;min-width:900px}.data-table th{position:sticky;top:0;background:#f8fafc;text-align:left;padding:11px 12px;font-size:11px;color:#64748b;border-bottom:1px solid var(--line)}.data-table td{padding:12px;border-bottom:1px solid #edf2f7;font-size:12px}.data-table tbody tr{cursor:pointer}.data-table tbody tr:hover{background:#f8fbff}.stock-name{font-weight:900}.stock-code{font-size:10px;color:#94a3b8}.score{font-weight:950;color:var(--blue)}.positive{color:var(--green);font-weight:800}.negative{color:var(--red);font-weight:800}.quality{display:inline-grid;place-items:center;width:25px;height:25px;border-radius:8px;font-weight:950}.quality.A{background:#dcfce7;color:#166534}.quality.B{background:#dbeafe;color:#1d4ed8}.quality.C{background:#ffedd5;color:#9a3412}.quality.D{background:#fee2e2;color:#991b1b}.stock-detail{margin-top:14px;background:#fff;border:1px solid var(--line);border-radius:20px;padding:22px}.stock-detail-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}.stock-detail h3{font-size:23px;margin:0 0 6px}.detail-kpis{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.mini-kpi{background:#f8fafc;border-radius:12px;padding:10px}.mini-kpi span{font-size:10px;color:#64748b;display:block}.mini-kpi b{font-size:17px}.sparkline{height:84px;width:100%;margin-top:12px}.empty-state{color:#94a3b8;text-align:center;padding:36px}.tabs{display:flex;gap:7px;margin-bottom:14px}.tabs button{border:1px solid #cbd5e1;background:#fff;padding:8px 15px;border-radius:999px;font-weight:850;cursor:pointer}.tabs button.active{background:#0f172a;color:#fff;border-color:#0f172a}.list-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.list-card{background:#fff;border:1px solid var(--line);border-radius:17px;padding:16px}.list-card-title{font-weight:950}.list-card-sub{font-size:11px;color:#64748b;margin-top:3px}.list-card-reason{font-size:11px;color:#334155;margin-top:9px}.split-grid{display:grid;grid-template-columns:1.1fr .9fr;gap:22px}.split-grid h3,.panel h3{font-size:18px;margin:0 0 12px}.bar-list,.compact-list{background:#fff;border:1px solid var(--line);border-radius:19px;padding:8px 16px}.bar-row{padding:12px 0;border-bottom:1px solid #edf2f7}.bar-row:last-child,.compact-row:last-child{border-bottom:0}.bar-head{display:flex;justify-content:space-between;font-size:12px;font-weight:900}.bar-track{height:7px;border-radius:999px;background:#e2e8f0;margin-top:8px;overflow:hidden}.bar-fill{height:100%;background:linear-gradient(90deg,#60a5fa,#2563eb);border-radius:999px}.bar-meta{font-size:10px;color:#64748b;margin-top:6px}.compact-row{padding:11px 0;border-bottom:1px solid #edf2f7}.compact-title{font-size:12px;font-weight:900}.compact-meta{font-size:10px;color:#64748b;margin-top:3px}.warning-list{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.warning-item{background:#fff7ed;border:1px solid #fed7aa;border-radius:15px;padding:13px}.warning-item strong{font-size:12px}.warning-item p{font-size:11px;color:#9a3412;margin:5px 0 0}.research-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}.panel{background:#fff;border:1px solid var(--line);border-radius:20px;padding:18px}.panel .compact-list{border:0;padding:0}.paper-kpis{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:10px}.paper-kpis div{background:#f8fafc;border-radius:11px;padding:9px}.paper-kpis span{font-size:9px;color:#64748b;display:block}.paper-kpis b{font-size:16px}footer{max-width:1180px;margin:80px auto 0;padding:26px 24px 40px;border-top:1px solid #dbe4ef;display:flex;justify-content:space-between;color:#64748b;font-size:11px}@media(max-width:980px){.metric-grid{grid-template-columns:repeat(3,1fr)}.filter-panel{grid-template-columns:repeat(3,1fr)}.list-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:760px){.topbar{padding:0 16px}.nav-toggle{display:block}.site-nav{display:none;position:absolute;top:64px;left:0;right:0;background:#0b1220;padding:14px 18px;flex-wrap:wrap}.site-nav.open{display:flex}.section-shell{padding:48px 16px 0}.hero{grid-template-columns:1fr;padding-top:48px}.hero-copy h1{font-size:46px}.regime-card{min-height:190px}.metric-grid{grid-template-columns:repeat(2,1fr);padding-top:20px}.section-head{align-items:flex-start;flex-direction:column}.section-head h2{font-size:29px}.action-grid,.split-grid,.research-grid,.warning-list,.list-grid{grid-template-columns:1fr}.filter-panel{grid-template-columns:1fr 1fr}.search-field{grid-column:1/-1}.stock-detail-grid{grid-template-columns:1fr}.detail-kpis{grid-template-columns:repeat(2,1fr)}footer{flex-direction:column;gap:8px}}@media(max-width:430px){.filter-panel{grid-template-columns:1fr}.metric-grid{grid-template-columns:1fr 1fr}.metric-value{font-size:21px}.action-card{padding:18px}.hero-copy h1{font-size:40px}}'
